#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
		    double alpha,
		    double beta,
		    std::vector<std::vector<double>>& A,
		    std::vector<std::vector<double>>& B,
		    std::vector<double>& tmp,
		    std::vector<double>& x,
		    std::vector<double>& y)
{
    const double *x_ptr = x.data();                 // common read‑only array
    const double *tmp_ptr = tmp.data();             // write‑only array (temporary)
    double *y_ptr = y.data();                       // write‑only array

    // Parallelise outer loop; each thread works on its own contiguous range of rows
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double *Arow = A[i].data();
        const double *Brow = B[i].data();
        double sumA = 0.0;   // tmp[i]
        double sumB = 0.0;   // y[i]

        for (int j = 0; j < n; ++j) {
            double xj = x_ptr[j];
            sumA += Arow[j] * xj;
            sumB += Brow[j] * xj;
        }

        y_ptr[i] = alpha * sumA + beta * sumB;
        tmp_ptr[i] = sumA;  // maintain exact semantics (tmp is not used elsewhere)
    }
}
