#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 const std::vector<std::vector<double>>& A,
                 const std::vector<std::vector<double>>& B)
{
    // Parallelise the outermost loop – each iteration is independent
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const double* const a_i = A[i].data();   // row i of A
        const double* const b_i = B[i].data();   // row i of B
        double* const c_i = C[i].data();        // row i of C

        // Loop over columns of B/C
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            const double bj = b_i[j];
            // k-loop over lower triangle (0 <= k < i)
            for (int k = 0; k < i; ++k) {
                const double aik = a_i[k];
                const double bk = B[k][j];
                // update C[k][j] as in the original code
                C[k][j] += alpha * bj * aik;
                sum += bk * aik;
            }
            // final update of C[i][j]
            c_i[j] = beta * c_i[j] + alpha * bj * a_i[i] + alpha * sum;
        }
    }
}
