extern "C" void kernel_jacobi_1d(int tsteps,
                                 int n,
                                 std::vector<double>& A,
                                 std::vector<double>& B) {
    // Constant used in the stencil – kept as a double literal to preserve
    // the exact original semantics.
    constexpr double inv3 = 0.33333;

    // Retrieve raw pointers for fast access.
    double *a = A.data();
    double *b = B.data();

    // OpenMP parallelises the outer loop; inner loops are trivially
    // vectorisable thanks to the `#pragma omp simd` directive.
    #pragma omp parallel for schedule(static)
    for (int t = 0; t < tsteps; ++t) {
        // First half‑step: A → B
        #pragma omp simd
        for (int i = 1; i < n - 1; ++i) {
            b[i] = inv3 * (a[i-1] + a[i] + a[i+1]);
        }

        // Second half‑step: B → A
        #pragma omp simd
        for (int i = 1; i < n - 1; ++i) {
            a[i] = inv3 * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
