void kernel_lu(int n,
               std::vector<std::vector<double>>& A) {
    // Ensure the matrix is contiguous in memory for best cache behavior
    std::vector<double*> rows(n);
    for (int i = 0; i < n; ++i)
        rows[i] = A[i].data();

    for (int i = 0; i < n; ++i) {
        double* Ai = rows[i];

        /* --- First part: j < i --- */
#pragma omp parallel for schedule(static)
        for (int j = 0; j < i; ++j) {
            double* Aj = rows[j];
            double sum = 0.0;
            for (int k = 0; k < j; ++k)
                sum += Ai[k] * Aj[k];
            Ai[j] -= sum;
            Ai[j] /= Aj[j];
        }

        /* --- Second part: j >= i --- */
#pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double* Aj = rows[j];
            double sum = 0.0;
            for (int k = 0; k < i; ++k)
