/* ---- Optimised kernel ---- */
/* Kernel:  B := alpha * A^T * B
 *   A : M x M   (upper triangular, but only the lower part is used)
 *   B : M x N   (updated in place)
 *
 * The routine is fully OpenMP‑parallelised over the outer i/j loops
 * and uses pointer arithmetic to improve cache utilisation.
 */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // collapsed parallelised outer loops to exploit all 8 threads
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            // inner k loop iterates over rows k > i
            for (int k = i + 1; k < m; ++k) {
                // A[k][i] is column 'i' of A
                sum += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * (B[i][j] + sum);
        }
    }
}
