#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // --------- 1. compute column means ------------------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    // --------- 2. subtract column means from each element -----------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        const double* mptr = mean.data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mptr[j];
        }
    }

    // --------- 3. compute covariance matrix (upper triangle) ---------------
    // we use a strip‑mining approach to keep cache lines used
    const double inv = 1.0 / static_cast<double>(n - 1);
    #pragma omp parallel for schedule(static, 1)
    for (int i = 0; i < m; ++i) {
        double* ci = cov[i].data();
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double val = sum * inv;
            ci[j] = val;
            cov[j][i] = val;   // fill symmetric counterpart
        }
    }
}
