```cpp
#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
			std::vector<std::vector<double>>& A,
			std::vector<std::vector<double>>& R,
			std::vector<std::vector<double>>& Q) {
    // Local copy of A to allow parallel read/write without race issues
    std::vector<std::vector<double>> A_copy = A;

    for (int k = 0; k < n; ++k) {
        double nrm = 0.0;

        // Compute squared norm of column k
        for (int i = 0; i < m; ++i) {
            double v = A_copy[i][k];
            nrm += v * v;
        }
        R[k][k] = std::sqrt(nrm);
        double inv_norm = 1.0 / R[k][k];

        // Compute Q column k
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A_copy[i][k] * inv_norm;
        }

        // Orthogonalize remaining columns
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;
            // dot product Q_col_k · A_col_j
            for (int i = 0; i < m; ++i) {
                rkj += Q[i][k] * A_copy[i][j];
            }
            R[k][j] = rkj;

            // A_col_j = A_col_j - Q_col_k * rkj
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A_copy[i][j] -= Q[i][k] * rkj;
            }
        }
    }

    // Copy the modified A back to the caller
    A = std::move(A_copy);
}
