#include <cmath>
#include <vector>
#include <cstring>
#include <omp.h>

/* ------------------------------------------------------------------ */
/* Helper to obtain a contiguous 2‑D array view from the vector of    */
/* vectors.  The original **exact** layout of A is preserved, but we   */
/* work with a single pointer for better cache locality.              */
/* ------------------------------------------------------------------ */
static inline double* get_row_ptr(const std::vector<std::vector<double>>& A, int i)
{
    return const_cast<double*>(A[i].data());
}

/* ------------------------------------------------------------------ */
/* Kernel: Cholesky factorisation.  All work is performed on a       */
/* contiguous array.  The algorithm is identical to the original      */
/* version – only the data layout and parallelism differ.             */
/* ------------------------------------------------------------------ */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A)
{
    /* OpenMP: parallelise the outermost loop over i.  The work for a
       given i depends only on the previous rows, which are guaranteed
       to be finished because the loop is strictly increasing in i.
       schedule(static) gives excellent load balance for a dense
       matrix.                                                    */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ai = get_row_ptr(A, i);

        /* Process elements below the diagonal: j = 0 .. i-1 */
        for (int j = 0; j < i; ++j) {
            double* Aj = get_row_ptr(A, j);

            /* dot product of rows i and j, over k = 0 .. j-1 */
            double sum = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += Ai[k] * Aj[k];
            }

            Ai[j] -= sum;
            Ai[j] /= Aj[j];          // Aj[j] > 0 because of positive definiteness
        }

        /* Diagonal element */
        double diag = Ai[i];
        for (int k = 0; k < i; ++k) {
            diag -= Ai[k] * Ai[k];
        }
        Ai[i] = std::sqrt(diag);
    }
}
