#include <vector>
#include <cstddef>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // All matrices are stored as contiguous row–major vectors of vectors.
    // We cast the data to raw pointers to avoid repeated bounds checking
    // and index arithmetic inside the hot loops.

#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i)
    {
        double* const C_row = C[i].data();          // pointer to the i‑th row of C
        const double* const A_row = A[i].data();    // pointer to the i‑th row of A

        // The outermost loop over j is kept separate to scale beta once per row.
        for (int j = 0; j < nj; ++j) {
            C_row[j] *= beta;
        }

        // Main multiply–accumulate loop, accumulating into C_row.
        for (int k = 0; k < nk; ++k) {
            const double aik = alpha * A_row[k];
            const double* const B_row = B[k].data();
            for (int j = 0; j < nj; ++j) {
                C_row[j] += aik * B_row[j];
            }
        }
    }
}
