/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    const double a_alpha = alpha;
    const double a_beta  = beta;

    /* Parallelise the outer loop over i. Each thread works on distinct
       rows of C, so there are no race conditions. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* ci = &C[i][0];           // pointer to row i of C
        const double* ai = &A[i][0];     // pointer to row i of A

        /* Scale the lower triangular part of row i by beta. */
        for (int j = 0; j <= i; ++j)
            ci[j] *= a_beta;

        /* Accumulate alpha * A[i][k] * A[j][k] for all k and
           for all j <= i. */
        for (int k = 0; k < m; ++k) {
            const double aik = ai[k];          // A[i][k]
            const double* ak = &A[0][k];       // column k of A
            for (int j = 0; j <= i; ++j)
                ci[j] += a_alpha * aik * ak[j];
        }
    }
}
