void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path)
{
    // Flatten the 2‑D vector into a 1‑D array for much better cache locality.
    // A copy is made to avoid affecting the original vector layout during
    // the computation.  The final results are written back into the
    // original 2‑D container.
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat.begin() + i * n);

    // Block size tuned empirically for typical cache sizes.
    constexpr int B = 64;

    // The standard triple loop, reordered for cache friendliness and
    // parallelised over the middle dimension.
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        int k_offset = k * n;
        for (int i = 0; i < n; ++i) {
            int i_offset = i * n;
            int dik = flat[i_offset + k];
            // If dik is a large value (e.g., INF) we can skip the inner loop,
            // but since the original code didn't optimize for INF we keep the
            // exact semantics and still perform the comparison.
            for (int bj = 0; bj < n; bj += B) {
                int end = std::min(bj + B, n);
                for (int j = bj; j < end; ++j) {
                    int new_val = dik + flat[k_offset + j];
                    int& dst = flat[i_offset + j];
                    if (new_val < dst) dst = new_val;
                }
            }
        }
    }

    // Copy the flattened results back into the original vector of vectors.
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n, path[i].begin());
}
