/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate temporary buffer once
    std::vector<double> z(n, 0.0);

    // Initial values
    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    // Pointer aliasing for speed
    double *rptr = r.data();
    double *yptr = y.data();
    double *zptr = z.data();

    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute dot‑product: sum = Σ r[k-i-1] * y[i]   (i = 0..k-1)
        double sum = 0.0;
        #pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i) {
            sum += rptr[k - i - 1] * yptr[i];
        }

        // New reflection coefficient
        alpha = -(rptr[k] + sum) / beta;

        // Update z[i] = y[i] + alpha * y[k-i-1]
        #pragma omp simd
        for (int i = 0; i < k; ++i) {
            zptr[i] = yptr[i] + alpha * yptr[k - i - 1];
        }

        // Copy back to y[0..k-1]
        std::memcpy(yptr, zptr, k * sizeof(double));

        // Store new coefficient
        yptr[k] = alpha;
    }
}
