/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B) {
    if (n <= 2) return;                     // nothing to update

    const double coeff = 0.2;
    const int inner = n - 2;                // number of inner rows/cols

    for (int t = 0; t < tsteps; ++t) {

        /* 1st half‑step: compute B from A */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= inner; ++i) {
            double* a_i   = A[i].data();
            double* a_ip1 = A[i+1].data();
            double* a_im1 = A[i-1].data();
            double* b_i   = B[i].data();

            for (int j = 1; j <= inner; ++j) {
                b_i[j] = coeff * ( a_i[j] + a_i[j-1] + a_i[j+1]
                                   + a_ip1[j] + a_im1[j] );
            }
        }

        /* 2nd half‑step: compute A from B */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= inner; ++i) {
            double* b_i   = B[i].data();
            double* b_ip1 = B[i+1].data();
            double* b_im1 = B[i-1].data();
            double* a_i   = A[i].data();

            for (int j = 1; j <= inner; ++j) {
                a_i[j] = coeff * ( b_i[j] + b_i[j-1] + b_i[j+1]
                                   + b_ip1[j] + b_im1[j] );
            }
        }
    }
}
