/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    // initialize y to zero
    std::fill(y.begin(), y.end(), 0.0);

    // buffer for local y contributions in each thread
    std::vector<std::vector<double>> local_y;

    #pragma omp parallel
    {
        // each thread has its own local y array
        std::vector<double> l_y(n, 0.0);

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            double ti = 0.0;
            const double* Ai = A[i].data();
            const double* xv = x.data();

            // compute tmp[i] = A[i] * x
            for (int j = 0; j < n; ++j)
                ti += Ai[j] * xv[j];

            tmp[i] = ti;

            // accumulate y += A[i] * tmp[i]
            for (int j = 0; j < n; ++j)
                l_y[j] += Ai[j] * ti;
        }

        // merge thread‑local results into global y
        #pragma omp critical
        {
            for (int j = 0; j < n; ++j)
                y[j] += l_y[j];
        }
    }
}
