    /* Compute q[i] = Σ_j (A[i][j] + p[j]) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        for (int j = 0; j < m; ++j) {
            sum += A[i][j] + p[j];
        }
