void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---------- compute mean ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += data[i][j];
        mean[j] = sum / static_cast<double>(n);
    }

    /* ---------- compute stddev ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double var = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            var += d * d;
        }
        var /= static_cast<double>(n);
        stddev[j] = std::sqrt(var);
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    /* ---------- normalize data ---------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double v = data[i][j] - mean[j];
            v *= inv_sqrt_n / stddev[j];
            data[i][j] = v;
        }
    }

    /* ---------- compute correlation ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            corr[i][j] = sum;
            corr[j][i] = sum;            // symmetry
        }
    }
    corr[m - 1][m - 1] = 1.0;
}
