/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
   with help from Allison Lake, Ting Zhou, and Tian Jin,
   based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Flatten the 2‑D table to a 1‑D array for cache friendliness.
    // table[i][j] -> flat[i * n + j]
    std::vector<int> flat(n * n, 0);

    // Inline match function (fast branchless form).
    auto match = [](int b1, int b2) -> int
    {
        return (b1 + b2 == 3);       // returns 1 if complementary else 0
    };

    // Parallelise over anti‑diagonals (i decreasing, j increasing).
    // Each anti‑diagonal (i+j == constant) can be computed independently.
#pragma omp parallel for schedule(static)
    for (int sum = 1; sum <= n - 1; ++sum) {
        // i ranges from max(0, sum-(n-1)) to min(sum, n-1)
        int i_start = std::max(0, sum - (n - 1));
        int i_end   = std::min(sum, n - 1);
        for (int i = i_start; i <= i_end; ++i) {
            int j = sum - i;
            if (j <= i) continue;  // ensure i < j

            int idx = i * n + j;
            int best = 0;

            // table[i][j-1]
            if (j - 1 >= 0)
                best = std::max(best, flat[i * n + (j - 1)]);

            // table[i+1][j]
            if (i + 1 < n)
                best = std::max(best, flat[(i + 1) * n + j]);

            // pair i and j
            int pairScore = match(seq[i], seq[j]);
            if (i + 1 < n && j - 1 >= 0) {
                best = std::max(best,
                                flat[(i + 1) * n + (j - 1)] + pairScore);
            }

            // split at k
            for (int k = i + 1; k < j; ++k) {
                int left  = flat[i * n + k];
                int right = flat[(k + 1) * n + j];
                best = std::max(best, left + right);
            }

            flat[idx] = best;
        }
    }

    // Copy back into the original 2‑D structure.
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            table[i][j] = flat[i * n + j];
}
