/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* flatten matrix for better data locality and faster random
       access. The jagged std::vector<vector<double>> is replaced
       with a flat 1‑D array that is built once here. The original
       A data are overwritten into this array. */
    std::vector<double> flatA;
    flatA.resize(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flatA[i * n + j] = A[i][j];

    /*--- LU factorisation --------------------------------------------------*/
    for (int i = 0; i < n; ++i) {
        /* --------- compute L(i,j)  (j < i) --------------------------------*/
        for (int j = 0; j < i; ++j) {
            double w = flatA[i * n + j];
#pragma omp simd reduction(-:w)  // reuse for inner dot product
            for (int k = 0; k < j; ++k)
                w -= flatA[i * n + k] * flatA[k * n + j];
            flatA[i * n + j] = w / flatA[j * n + j];
        }

        /* --------- compute U(i,j)  (j >= i) --------------------------------*/
#pragma omp simd
        for (int j = i; j < n; ++j) {
            double w = flatA[i * n + j];
            for (int k = 0; k < i; ++k)
                w -= flatA[i * n + k] * flatA[k * n + j];
            flatA[i * n + j] = w;
        }
    }

    /*--- Forward substitution Ly = b --------------------------------------*/
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j)
            w -= flatA[i * n + j] * y[j];
        y[i] = w;
    }

    /*--- Backward substitution Ux = y -------------------------------------*/
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        for (int j = i + 1; j < n; ++j)
            w -= flatA[i * n + j] * x[j];
        x[i] = w / flatA[i * n + i];
    }

    /*--- copy result back to the original matrix structure ---------------*/
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = flatA[i * n + j];
}
