                auto& Aj      = Ai[j];
                auto& Bjp     = Bi[j+1];
                auto& Bjm     = Bi[j-1];
                for (int k = 1; k < n - 1; ++k)
                {
                    double val = Bj[k];
                    Aj[k] = coeff * (Bip[j][k] - 2.0 * val + Bim[j][k])
                         + coeff * (Bjp[k] - 2.0 * val + Bjm[k])
                         + coeff * (Bip[j][k+1] - 2.0 * val + Bip[j][k-1])
                         + val;
                }
            }
        }
    }
