        for (int i = 1; i <= n - 2; ++i) {
            double * row_im1 = rowPtrs[i - 1];
            double * row_i   = rowPtrs[i];
            double * row_ip1 = rowPtrs[i + 1];

            for (int j = 1; j <= n - 2; ++j) {
                // Unroll the sum manually – this removes 9 separate
                // array accesses and let the compiler apply vectorisation.
                double s = row_im1[j-1] + row_im1[j]   + row_im1[j+1]   +
                           row_i  [j-1] + row_i  [j]   + row_i  [j+1]   +
