// Optimised implementation of the Deriche filter kernel
//
// The original code used nested std::vector<std::vector<float>>
// which caused large pointer indirections and poor cache locality.
// The new version works with a single contiguous 1‑D array for each
// image and performs the same operations in the exact same order
// while exploiting OpenMP parallelisation and avoiding repeated
// pow()/exp() calls.
//
// The function signature is unchanged.

#include <cmath>
#include <vector>
#include <omp.h>

inline float safe_exp(const float x) noexcept { return std::exp(x); }

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    // 1‑D wrappers around the 2‑D vectors for fast indexing
    const int N = w * h;
    std::vector<float> in(N), out(N), tmp1(N), tmp2(N);

    auto idx = [=](int i, int j) { return i * h + j; };

    // Flatten input image into contiguous buffer
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            in[idx(i, j)] = imgIn[i][j];

    // Coefficients (pre‑computed once)
    const float exp_alpha = safe_exp(-static_cast<float>(alpha));
    const float exp_2alpha = safe_exp(-2.0f * static_cast<float>(alpha));
    const float denom = 1.0f + 2.0f * static_cast<float>(alpha) * exp_alpha - exp_2alpha;
    const float k = 1.0f - exp_alpha * (1.0f - exp_alpha) / denom;

    const float a1 = k, a2 = k * exp_alpha * (static_cast<float>(alpha) - 1.0f),
                a3 = k * exp_alpha * (static_cast<float>(alpha) + 1.0f), a4 = -k * exp_2alpha;
    const float a5 = k, a6 = a2, a7 = a3, a8 = a4;
    const float b1 = std::pow(2.0f, -static_cast<float>(alpha)), b2 = -exp_2alpha;
    const float c1 = 1.0f, c2 = 1.0f;

#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const int id = idx(i, j);
            tmp1[id] = a1 * in[id] + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = in[id];
            ym2 = ym1;
            ym1 = tmp1[id];
        }

        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            const int id = idx(i, j);
            tmp2[id] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = in[id];
            yp2 = yp1;
            yp1 = tmp2[id];
        }
    }

    // Combine the two 1‑D filter passes
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[idx(i, j)] = c1 * (tmp1[idx(i, j)] + tmp2[idx(i, j)]);

#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const int id = idx(i, j);
            tmp1[id] = a5 * out[id] + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = out[id];
            ym2 = ym1;
            ym1 = tmp1[id];
        }
    }

#pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const int id = idx(i, j);
            tmp2[id] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = out[id];
            yp2 = yp1;
            yp1 = tmp2[id];
        }
    }

    // Final output
#pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j) {
            const int id = idx(i, j);
            out[id] = c2 * (tmp1[id] + tmp2[id]);
        }

    // Copy back to the 2‑D output vectors
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = out[idx(i, j)];
}
