#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    // pre‑compute constants
    const double DX  = 1.0 / n;
    const double DY  = 1.0 / n;
    const double DT  = 1.0 / tsteps;
    const double B1  = 2.0;
    const double B2  = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a    = -mul1 / 2.0;
    const double b    = 1.0 + mul1;
    const double c    = a;
    const double d    = -mul2 / 2.0;
    const double e    = 1.0 + mul2;
    const double f    = d;
    const int   m     = n - 2;           // interior size

    // acquire pointers to the underlying flat data for speed
    double* udat = new double[n * n];
    double* vdat = new double[n * n];
    double* pdat = new double[n * n];
    double* qdat = new double[n * n];

    // flatten the 2‑D vectors once
    for (int i = 0; i < n; ++i)
    {
        std::copy(u[i].begin(), u[i].end(), &udat[i * n]);
        std::copy(v[i].begin(), v[i].end(), &vdat[i * n]);
        std::copy(p[i].begin(), p[i].end(), &pdat[i * n]);
        std::copy(q[i].begin(), q[i].end(), &qdat[i * n]);
    }

    // main time stepping loop
    for (int t = 1; t <= tsteps; ++t)
    {
        // ---------- first sweep (v from u) ----------
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            const int idxBase = i * n;

            // boundary initialization
            vdat[idxBase + 0] = 1.0;
            pdat[idxBase + 0] = 0.0;
            qdat[idxBase + 0] = vdat[idxBase + 0];

            // forward sweep on j
            for (int j = 1; j < n - 1; ++j)
            {
                double& p_val = pdat[idxBase + j];
                const double denom = a * pdat[idxBase + j - 1] + b;
                p_val = -c / denom;
                const double q_val =
                    (-d * udat[j * n + (i - 1)]
                     + (1.0 + 2.0 * d) * udat[j * n + i]
                     - f * udat[j * n + (i + 1)]
                     - a * qdat[idxBase + j - 1]) / denom;
                qdat[idxBase + j] = q_val;
            }

            // boundary at the top
            vdat[(n - 1) * n + i] = 1.0;

            // backward sweep on j
            for (int j = n - 2; j >= 1; --j)
            {
                vdat[j * n + i] =
                    pdat[idxBase + j] * vdat[(j + 1) * n + i]
                    + qdat[idxBase + j];
            }
        }

        // ---------- second sweep (u from v) ----------
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            const int idxBase = i * n;

            // boundary initialization
            udat[idxBase + 0] = 1.0;
            pdat[idxBase + 0] = 0.0;
            qdat[idxBase + 0] = udat[idxBase + 0];

            // forward sweep on j
            for (int j = 1; j < n - 1; ++j)
            {
                double& p_val = pdat[idxBase + j];
                const double denom = d * pdat[idxBase + j - 1] + e;
                p_val = -f / denom;
                const double q_val =
                    (-a * vdat[(i - 1) * n + j]
                     + (1.0 + 2.0 * a) * vdat[idxBase + j]
                     - c * vdat[(i + 1) * n + j]
                     - d * qdat[idxBase + j - 1]) / denom;
                qdat[idxBase + j] = q_val;
            }

            // boundary at the right
            udat[idxBase + (n - 1)] = 1.0;

            // backward sweep on j
            for (int j = n - 2; j >= 1; --j)
            {
                udat[idxBase + j] =
                    pdat[idxBase + j] * udat[idxBase + (j + 1)]
                    + qdat[idxBase + j];
            }
        }
    }

    // copy back flattened data into the 2‑D vectors
    for (int i = 0; i < n; ++i)
    {
        std::copy(&udat[i * n], &udat[i * n] + n, u[i].begin());
        std::copy(&vdat[i * n], &vdat[i * n] + n, v[i].begin());
        std::copy(&pdat[i * n], &pdat[i * n] + n, p[i].begin());
        std::copy(&qdat[i * n], &qdat[i * n] + n, q[i].begin());
    }

    delete[] udat;
    delete[] vdat;
    delete[] pdat;
    delete[] qdat;
}
